xpath.attribute:
format_float(
    float(format_float(
        sum(
            docto['imp_pagado'] if docto['moneda'] == moneda else docto['imp_pagado'] / (docto['equivalencia'] or 1)
            for docto in docto_relationado_list
        ),
        precision=2
    )) * (tipo_cambio or 1),
    precision=2
)
